function solve(nums: number[], queries: number[][]): number[] {
    // Precompute the popcount-depth for each number in nums
    const depthMap = new Map<number, number>();

    // Function to compute popcount-depth
    function getDepth(x: number): number {
        let depth = 0;
        while (x > 0) {
            x = x & (x - 1); // Clear the least significant bit
            depth++;
        }
        return depth;
    }

    // Precompute the depth for each number in nums
    for (const num of nums) {
        depthMap.set(num, getDepth(num));
    }

    // For efficient range queries, we use a segment tree
    // Since k can be up to 5, we can use a 2D array for each k
    // We'll use a binary indexed tree (Fenwick Tree) for each k
    const BIT = Array(6).fill(0).map(() => new Array(nums.length + 1).fill(0));

    // Initialize the BITs
    for (let i = 0; i < nums.length; i++) {
        const depth = depthMap.get(nums[i])!;
        BIT[depth][i + 1] = 1;
    }

    // Function to update the BIT
    function update(bit: number[], index: number, value: number) {
        while (index <= nums.length) {
            bit[index] += value;
            index += index & -index;
        }
    }

    // Function to query the prefix sum up to index
    function query(bit: number[], index: number): number {
        let res = 0;
        while (index > 0) {
            res += bit[index];
            index -= index & -index;
        }
        return res;
    }

    // Function to query the range [l, r]
    function rangeQuery(bit: number[], l: number, r: number): number {
        return query(bit, r) - query(bit, l);
    }

    // Process the queries
    const answer: number[] = [];

    for (const query of queries) {
        if (query[0] === 1) {
            // Query type 1: count numbers with depth k in [l, r]
            const l = query[1];
            const r = query[2];
            const k = query[3];
            const count = rangeQuery(BIT[k], l, r);
            answer.push(count);
        } else {
            // Query type 2: update nums[idx] to val
            const idx = query[1];
            const val = query[2];
            const oldVal = nums[idx];
            const oldDepth = depthMap.get(oldVal)!;
            const newDepth = getDepth(val);

            // Update the BITs
            update(BIT[oldDepth], idx + 1, -1);
            update(BIT[newDepth], idx + 1, 1);

            // Update the nums array and the depth map
            nums[idx] = val;
            depthMap.set(val, newDepth);
        }
    }

    return answer;
}

class FenwickTree {
    constructor(private size: number) {
        this.tree = new Array(size + 1).fill(0);
    }

    update(index: number, delta: number) {
        while (index <= this.size) {
            this.tree[index] += delta;
            index += index & -index;
        }
    }

    query(index: number): number {
        let res = 0;
        while (index > 0) {
            res += this.tree[index];
            index -= index & -index;
        }
        return res;
    }
}

